import { z } from "zod";

export const dnsLookupRequestSchema = z.object({
  domain: z.string().max(253),
  types: z
    .array(z.enum(["A", "AAAA", "MX", "TXT", "NS", "CNAME", "SOA"]))
    .optional()
    .default(["A"]),
  whois: z.boolean().optional().default(false),
});

export const dnsRecordSchema = z.object({
  type: z.string(),
  name: z.string(),
  data: z.string(),
  ttl: z.number(),
  priority: z.number().optional(),
});

export const dnsLookupResponseSchema = z.object({
  domain: z.string(),
  records: z.array(dnsRecordSchema),
  whois: z
    .object({
      registrar: z.string().nullable(),
      creation_date: z.string().nullable(),
      expiration_date: z.string().nullable(),
      name_servers: z.array(z.string()),
    })
    .nullable(),
});

export type DnsLookupRequest = z.infer<typeof dnsLookupRequestSchema>;
export type DnsRecord = z.infer<typeof dnsRecordSchema>;
export type DnsLookupResponse = z.infer<typeof dnsLookupResponseSchema>;
